3	const NR_GRAPHQL_URL = 'https://api.newrelic.com/graphql';
4	
5	interface NerdGraphResponse {
6		data: {
7			actor: {
8				account: {
9					current: { results: Array<Record<string, unknown>> };
10					previous: { results: Array<Record<string, unknown>> };
11				};
12			};
13		};
14	}
15	
16	export async function fetchNewRelicErrors({
17		apiKey,
18		accountId,
19	}: {
20		apiKey: string;
21		accountId: string;
22	}): Promise<NewRelicError[]> {
23		const baseNrql =
24			"SELECT count(*) as errorCount, latest(error.class) as errorClass, latest(request.uri) as requestUri FROM TransactionError WHERE appName LIKE '%Recommendations Service (production)%' FACET error.class, error.message, transactionName LIMIT 30";
25	
26		const currentNrql = JSON.stringify(`${baseNrql} SINCE 24 HOURS AGO`);
27		const previousNrql = JSON.stringify(
28			`${baseNrql} SINCE 48 HOURS AGO UNTIL 24 HOURS AGO`,
29		);
30	
31		const query = `{
32	    actor {
33	      account(id: ${accountId}) {
34	        current: nrql(query: ${currentNrql}) { results }
35	        previous: nrql(query: ${previousNrql}) { results }
36	      }
37	    }
38	  }`;
