import { RollbarError } from './types';

const ROLLBAR_API_URL = 'https://api.rollbar.com/api/1';

interface RollbarItemListItem {
	id: number;
	fingerprint: string;
	title: string;
	level: string;
	status: string;
	total_occurrences: number;
	first_occurrence_timestamp: number;
	last_occurrence_timestamp: number;
}

interface RollbarItemListResponse {
	result: {
		items: RollbarItemListItem[];
		page: number;
		total_count: number;
	};
}

interface RollbarFrame {
	filename: string;
	lineno: number;
	method: string;
}

interface RollbarOccurrence {
	data: {
		custom?: { correlationId?: string };
		body?: {
			trace_chain?: Array<{ frames?: RollbarFrame[] }>;
			trace?: { frames?: RollbarFrame[] };
		};
	};
}

interface RollbarInstancesResponse {
	result: { instances: RollbarOccurrence[] };
}

function parseTitle({ title }: { title: string }): [string, string] {
	const colonIdx = title.indexOf(': ');
	if (colonIdx === -1) return [title, ''];
	return [title.slice(0, colonIdx), title.slice(colonIdx + 2)];
}

async function fetchOccurrenceDetails({
	headers,
	itemId,
}: {
	headers: Record<string, string>;
	itemId: number;
}): Promise<{ stackTrace: string | null; correlationId: string | null }> {
	const url = `${ROLLBAR_API_URL}/item/${itemId}/instances/?per_page=1`;
	const resp = await fetch(url, { headers });
	if (!resp.ok) return { stackTrace: null, correlationId: null };

	const json = (await resp.json()) as RollbarInstancesResponse;
	const occurrence = json.result.instances[0];

	const correlationId = occurrence?.data?.custom?.correlationId ?? null;
	const frames =
		occurrence?.data?.body?.trace_chain?.[0]?.frames ??
		occurrence?.data?.body?.trace?.frames ??
		[];

	const stackTrace =
		frames.length === 0
			? null
			: frames
					.slice(0, 10)
					.map((f) => `  at ${f.method} (${f.filename}:${f.lineno})`)
					.join('\n');

	return { stackTrace, correlationId };
}

export async function fetchRollbarErrors({
	readToken,
}: {
	readToken: string;
}): Promise<RollbarError[]> {
	const rollbarHeaders = { 'X-Rollbar-Access-Token': readToken };
	const now = Math.floor(Date.now() / 1000);
	const since24h = now - 86400;

	const allItems: RollbarItemListItem[] = [];
	let page = 1;

	while (page <= 5) {
		const url = `${ROLLBAR_API_URL}/items/?status=active&per_page=100&page=${page}&order=desc`;
		const resp = await fetch(url, { headers: rollbarHeaders });
		if (!resp.ok) break;

		const json = (await resp.json()) as RollbarItemListResponse;
		const items = json.result.items;
		if (items.length === 0) break;

		const recentItems = items.filter((i) => i.last_occurrence_timestamp >= since24h);
		allItems.push(...recentItems);

		const lastItem = items[items.length - 1];
		if (!lastItem || lastItem.last_occurrence_timestamp < since24h) break;

		page++;
	}

	const topItems = allItems
		.sort((a, b) => b.total_occurrences - a.total_occurrences)
		.slice(0, 50);

	const errors = await Promise.all(
		topItems.map(async (item, idx) => {
			const [errorClass, errorMessage] = parseTitle({ title: item.title });

			let stackTrace: string | null = null;
			let correlationId: string | null = null;

			if (idx < 10) {
				const details = await fetchOccurrenceDetails({
					headers: rollbarHeaders,
					itemId: item.id,
				});
				stackTrace = details.stackTrace;
				correlationId = details.correlationId;
			}

			return {
				itemId: item.id,
				errorClass,
				errorMessage,
				level: item.level,
				totalOccurrences: item.total_occurrences,
				firstOccurrenceTimestamp: item.first_occurrence_timestamp,
				lastOccurrenceTimestamp: item.last_occurrence_timestamp,
				fingerprint: item.fingerprint,
				isNew: item.first_occurrence_timestamp >= since24h,
				stackTrace,
				correlationId,
				rollbarUrl: `https://rollbar.com/item/${item.id}/`,
			};
		}),
	);

	return errors;
}

