import { Injectable, Scope } from '@nestjs/common';
import * as newrelic from 'newrelic';

import { EnvConfigService } from '@modules/env-config/env-config.service';

import { NODE_ENV, SERVER_NAME } from '@constants/env-variables.constant';

@Injectable({ scope: Scope.REQUEST })
export class NewrelicService {
	private group = 'default';
	public readonly instance: typeof newrelic = newrelic;

	constructor(private readonly envConfig: EnvConfigService) {}

	setGroup({ group }: { group: string }): void {
		this.group = group;
	}

	recordMetric({
		module,
		metricName,
		value,
	}: {
		module: string;
		metricName: string;
		value: number;
	}): void {
		this.instance.recordMetric(`${module}/${this.group}/${metricName}`, value);
	}

	incrementMetric({ module, metricName }: { module: string; metricName: string }): void {
		this.instance.incrementMetric(`${module}/${this.group}/${metricName}`, 1);
	}

	attachMetadata(): void {
		this.instance.addCustomAttribute(
			'environment',
			this.envConfig.get<string>({ key: NODE_ENV }),
		);
		this.instance.addCustomAttribute(
			'serverName',
			this.envConfig.get<string>({ key: SERVER_NAME }),
		);
	}

	getLinkingMetadata(): newrelic.LinkingMetadata {
		return this.instance.getLinkingMetadata();
	}
}

