import type {
	ErrorGroup,
	MetricComparison,
	MetricPoint,
	MetricSeries,
	SlowQuery,
} from './types';

const NR_GRAPHQL_URL = 'https://api.newrelic.com/graphql';
const APP_FILTER = "appName LIKE '%Recommendations Service (production)%'";

interface NrRow {
	[key: string]: unknown;
}

interface NrResult {
	results: NrRow[];
}

interface NerdGraphResponse {
	data: {
		actor: {
			account: {
				errorsCurrent: NrResult;
				errorsPrevious: NrResult;
				throughput: NrResult;
				throughputMonthly: NrResult;
				responseTime: NrResult;
				responseTimeP95agg: NrResult;
				responseTimeMonthly: NrResult;
				errorRate: NrResult;
				errorRateMonthly: NrResult;
				apdex: NrResult;
				apdexMonthly: NrResult;
				cpu: NrResult;
				memory: NrResult;
				slowQueries: NrResult;
			};
		};
	};
}

function extractValue({ value }: { value: unknown }): number {
	if (typeof value === 'number') return value;
	if (typeof value === 'object' && value !== null) {
		const entries = Object.entries(value as Record<string, unknown>);
		const first = entries[0];
		return first ? Number(first[1]) || 0 : 0;
	}
	return 0;
}

function getField({ row, field }: { row: NrRow; field: string }): number {
	return extractValue({ value: row[field] });
}

function buildTimeseries({ rows, field }: { rows: NrRow[]; field: string }): MetricPoint[] {
	return rows.map((row) => ({
		beginTimeSeconds: typeof row['beginTimeSeconds'] === 'number' ? row['beginTimeSeconds'] : 0,
		endTimeSeconds: typeof row['endTimeSeconds'] === 'number' ? row['endTimeSeconds'] : 0,
		value: getField({ row, field }),
	}));
}

function average({ points }: { points: MetricPoint[] }): number {
	if (points.length === 0) return 0;
	return points.reduce((sum, p) => sum + p.value, 0) / points.length;
}

function buildSeries({
	name,
	unit,
	rows,
	field,
	monthlyValue,
}: {
	name: string;
	unit: string;
	rows: NrRow[];
	field: string;
	monthlyValue: number;
}): MetricSeries {
	const timeseries = buildTimeseries({ rows, field });
	const avg24h = average({ points: timeseries });
	const changePercent =
		monthlyValue === 0
			? null
			: Math.round(((avg24h - monthlyValue) / monthlyValue) * 100);
	return { name, unit, timeseries, avg24h, monthlyAvg: monthlyValue, changePercent };
}

function q({ nrql }: { nrql: string }): string {
	return JSON.stringify(nrql);
}

export async function fetchNewRelicMetrics({
	apiKey,
	accountId,
}: {
	apiKey: string;
	accountId: string;
}): Promise<{
	errorGroups: ErrorGroup[];
	throughput: MetricSeries;
	responseTime: MetricSeries;
	errorRate: MetricSeries;
	apdex: MetricSeries;
	cpu: MetricSeries | null;
	memory: MetricSeries | null;
	slowQueries: SlowQuery[];
	comparison: MetricComparison[];
}> {
	const query = `{
    actor {
      account(id: ${accountId}) {
        errorsCurrent: nrql(query: ${q({ nrql: `SELECT count(*) as errorCount, latest(error.class) as errorClass, latest(request.uri) as requestUri FROM TransactionError WHERE ${APP_FILTER} FACET error.class, error.message, transactionName LIMIT 30 SINCE 24 HOURS AGO` })}) { results }
        errorsPrevious: nrql(query: ${q({ nrql: `SELECT count(*) as errorCount FROM TransactionError WHERE ${APP_FILTER} FACET error.class, error.message, transactionName LIMIT 30 SINCE 48 HOURS AGO UNTIL 24 HOURS AGO` })}) { results }
        throughput: nrql(query: ${q({ nrql: `SELECT rate(count(*), 1 minute) as throughput FROM Transaction WHERE ${APP_FILTER} SINCE 24 HOURS AGO TIMESERIES 1 hour` })}) { results }
        throughputMonthly: nrql(query: ${q({ nrql: `SELECT rate(count(*), 1 minute) as throughput FROM Transaction WHERE ${APP_FILTER} SINCE 30 DAYS AGO` })}) { results }
        responseTime: nrql(query: ${q({ nrql: `SELECT average(duration) as avgSec FROM Transaction WHERE ${APP_FILTER} SINCE 24 HOURS AGO TIMESERIES 1 hour` })}) { results }
        responseTimeP95agg: nrql(query: ${q({ nrql: `SELECT percentile(duration, 95) as p95Sec FROM Transaction WHERE ${APP_FILTER} SINCE 24 HOURS AGO` })}) { results }
        responseTimeMonthly: nrql(query: ${q({ nrql: `SELECT average(duration) as avgSec, percentile(duration, 95) as p95Sec FROM Transaction WHERE ${APP_FILTER} SINCE 30 DAYS AGO` })}) { results }
        errorRate: nrql(query: ${q({ nrql: `SELECT percentage(count(*), WHERE error IS true) as errorRate FROM Transaction WHERE ${APP_FILTER} SINCE 24 HOURS AGO TIMESERIES 1 hour` })}) { results }
        errorRateMonthly: nrql(query: ${q({ nrql: `SELECT percentage(count(*), WHERE error IS true) as errorRate FROM Transaction WHERE ${APP_FILTER} SINCE 30 DAYS AGO` })}) { results }
        apdex: nrql(query: ${q({ nrql: `SELECT apdex(duration, t: 0.5) as apdex FROM Transaction WHERE ${APP_FILTER} SINCE 24 HOURS AGO TIMESERIES 1 hour` })}) { results }
        apdexMonthly: nrql(query: ${q({ nrql: `SELECT apdex(duration, t: 0.5) as apdex FROM Transaction WHERE ${APP_FILTER} SINCE 30 DAYS AGO` })}) { results }
