	const memorySeries =
		memoryRows.length === 0
			? null
			: buildSeries({
					name: 'Memory',
					unit: '%',
					rows: memoryRows,
					field: 'memoryPercent',
					monthlyValue: 0,
				});

	const slowQueries: SlowQuery[] = acct.slowQueries.results
		.filter((row) => getField({ row, field: 'maxMs' }) > 0)
		.map((row) => ({
			transactionName: String(row['name'] ?? ''),
			maxDurationMs: Math.round(getField({ row, field: 'maxMs' })),
			avgDurationMs: Math.round(getField({ row, field: 'avgMs' })),
			count: Math.round(getField({ row, field: 'count' })),
		}));

	const comparison: MetricComparison[] = [
		{
			label: 'Throughput',
			value24h: Math.round(throughputSeries.avg24h * 10) / 10,
			valueMonthly: Math.round(throughputMonthlyAvg * 10) / 10,
			changePercent: throughputSeries.changePercent,
			unit: 'req/min',
		},
		{
			label: 'Response Time (avg)',
			value24h: Math.round(responseTimeSeriesInMs.avg24h),
			valueMonthly: Math.round(rtMonthlyAvg),
			changePercent: responseTimeSeriesInMs.changePercent,
			unit: 'ms',
		},
		{
			label: 'Response Time (P95)',
			value24h: Math.round(rtP95agg24h),
			valueMonthly: Math.round(rtMonthlyP95),
			changePercent: rtP95ChangePercent,
			unit: 'ms',
		},
		{
			label: 'Error Rate',
			value24h: Math.round(errorRateSeries.avg24h * 100) / 100,
			valueMonthly: Math.round(errorRateMonthlyAvg * 100) / 100,
			changePercent: errorRateSeries.changePercent,
			unit: '%',
