import { writeFileSync } from 'node:fs';

import { fetchNewRelicMetrics } from './newrelic-client';
import type { Alert, AlertType, Digest } from './types';

const THRESHOLDS = {
	errorRate: { warning: 1, critical: 5 },
	responseTimeAvgMs: { warning: 1000, critical: 2000 },
	apdex: { warning: 0.85, critical: 0.7 },
	cpu: { warning: 70, critical: 85 },
	throughputDropPercent: -50,
} as const;

function detectAlerts({
	errorRate,
	responseTimeMs,
	apdex,
	cpu,
	throughputCurrent,
	throughputMonthly,
}: {
	errorRate: number;
	responseTimeMs: number;
	apdex: number;
	cpu: number | null;
	throughputCurrent: number;
	throughputMonthly: number;
}): Alert[] {
	const alerts: Alert[] = [];

	if (errorRate >= THRESHOLDS.errorRate.critical) {
		alerts.push({
			type: 'HIGH_ERROR_RATE' as AlertType,
			metric: 'Error Rate',
			currentValue: Math.round(errorRate * 100) / 100,
			threshold: THRESHOLDS.errorRate.critical,
			severity: 'CRITICAL',
			description: `Error rate ${errorRate.toFixed(2)}% exceeds critical threshold of ${THRESHOLDS.errorRate.critical}%`,
		});
	} else if (errorRate >= THRESHOLDS.errorRate.warning) {
		alerts.push({
			type: 'HIGH_ERROR_RATE' as AlertType,
			metric: 'Error Rate',
			currentValue: Math.round(errorRate * 100) / 100,
			threshold: THRESHOLDS.errorRate.warning,
			severity: 'WARNING',
			description: `Error rate ${errorRate.toFixed(2)}% exceeds warning threshold of ${THRESHOLDS.errorRate.warning}%`,
		});
	}

	if (responseTimeMs >= THRESHOLDS.responseTimeAvgMs.critical) {
		alerts.push({
			type: 'SLOW_RESPONSE' as AlertType,
			metric: 'Response Time',
			currentValue: Math.round(responseTimeMs),
			threshold: THRESHOLDS.responseTimeAvgMs.critical,
			severity: 'CRITICAL',
			description: `Avg response time ${Math.round(responseTimeMs)}ms exceeds critical threshold of ${THRESHOLDS.responseTimeAvgMs.critical}ms`,
		});
	} else if (responseTimeMs >= THRESHOLDS.responseTimeAvgMs.warning) {
		alerts.push({
			type: 'SLOW_RESPONSE' as AlertType,
			metric: 'Response Time',
			currentValue: Math.round(responseTimeMs),
			threshold: THRESHOLDS.responseTimeAvgMs.warning,
			severity: 'WARNING',
			description: `Avg response time ${Math.round(responseTimeMs)}ms exceeds warning threshold of ${THRESHOLDS.responseTimeAvgMs.warning}ms`,
		});
	}

	if (apdex > 0 && apdex <= THRESHOLDS.apdex.critical) {
		alerts.push({
			type: 'SLOW_RESPONSE' as AlertType,
			metric: 'Apdex',
			currentValue: Math.round(apdex * 1000) / 1000,
			threshold: THRESHOLDS.apdex.critical,
			severity: 'CRITICAL',
			description: `Apdex ${apdex.toFixed(3)} below critical threshold of ${THRESHOLDS.apdex.critical}`,
		});
	} else if (apdex > 0 && apdex <= THRESHOLDS.apdex.warning) {
		alerts.push({
			type: 'SLOW_RESPONSE' as AlertType,
			metric: 'Apdex',
			currentValue: Math.round(apdex * 1000) / 1000,
			threshold: THRESHOLDS.apdex.warning,
			severity: 'WARNING',
			description: `Apdex ${apdex.toFixed(3)} below warning threshold of ${THRESHOLDS.apdex.warning}`,
		});
	}

	if (cpu !== null && cpu >= THRESHOLDS.cpu.critical) {
		alerts.push({
			type: 'HIGH_CPU' as AlertType,
			metric: 'CPU',
			currentValue: Math.round(cpu * 10) / 10,
			threshold: THRESHOLDS.cpu.critical,
			severity: 'CRITICAL',
			description: `CPU ${cpu.toFixed(1)}% exceeds critical threshold of ${THRESHOLDS.cpu.critical}%`,
		});
