import type {
	ErrorGroup,
	MetricComparison,
	MetricPoint,
	MetricSeries,
	SlowQuery,
} from './types';

const NR_GRAPHQL_URL = 'https://api.newrelic.com/graphql';
const APP_FILTER = "appName LIKE '%Recommendations Service (production)%'";

interface NrRow {
	[key: string]: unknown;
}

interface NrResult {
	results: NrRow[];
}

interface NerdGraphResponse {
	data: {
		actor: {
			account: {
				errorsCurrent: NrResult;
				errorsPrevious: NrResult;
				throughput: NrResult;
				throughputMonthly: NrResult;
				responseTime: NrResult;
				responseTimeP95agg: NrResult;
				responseTimeMonthly: NrResult;
				errorRate: NrResult;
				errorRateMonthly: NrResult;
				apdex: NrResult;
				apdexMonthly: NrResult;
				cpu: NrResult;
				memory: NrResult;
				slowQueries: NrResult;
			};
		};
	};
}

function extractValue({ value }: { value: unknown }): number {
	if (typeof value === 'number') return value;
	if (typeof value === 'object' && value !== null) {
		const entries = Object.entries(value as Record<string, unknown>);
		const first = entries[0];
		return first ? Number(first[1]) || 0 : 0;
	}
	return 0;
}

function getField({ row, field }: { row: NrRow; field: string }): number {
	return extractValue({ value: row[field] });
}

function buildTimeseries({ rows, field }: { rows: NrRow[]; field: string }): MetricPoint[] {
	return rows.map((row) => ({
		beginTimeSeconds: typeof row['beginTimeSeconds'] === 'number' ? row['beginTimeSeconds'] : 0,
		endTimeSeconds: typeof row['endTimeSeconds'] === 'number' ? row['endTimeSeconds'] : 0,
		value: getField({ row, field }),
	}));
}

function average({ points }: { points: MetricPoint[] }): number {
	if (points.length === 0) return 0;
	return points.reduce((sum, p) => sum + p.value, 0) / points.length;
}

function buildSeries({
	name,
	unit,
	rows,
	field,
	monthlyValue,
}: {
	name: string;
	unit: string;
	rows: NrRow[];
	field: string;
	monthlyValue: number;
}): MetricSeries {
	const timeseries = buildTimeseries({ rows, field });
	const avg24h = average({ points: timeseries });
	const changePercent =
		monthlyValue === 0
			? null
			: Math.round(((avg24h - monthlyValue) / monthlyValue) * 100);
	return { name, unit, timeseries, avg24h, monthlyAvg: monthlyValue, changePercent };
}

function q({ nrql }: { nrql: string }): string {
	return JSON.stringify(nrql);
}

export async function fetchNewRelicMetrics({
	apiKey,
	accountId,
}: {
	apiKey: string;
	accountId: string;
}): Promise<{
	errorGroups: ErrorGroup[];
	throughput: MetricSeries;
	responseTime: MetricSeries;
	errorRate: MetricSeries;
	apdex: MetricSeries;
	cpu: MetricSeries | null;
	memory: MetricSeries | null;
	slowQueries: SlowQuery[];
	comparison: MetricComparison[];
}> {
	const query = `{
    actor {
      account(id: ${accountId}) {
        errorsCurrent: nrql(query: ${q({ nrql: `SELECT count(*) as errorCount, latest(error.class) as errorClass, latest(request.uri) as requestUri FROM TransactionError WHERE ${APP_FILTER} FACET error.class, error.message, transactionName LIMIT 30 SINCE 24 HOURS AGO` })}) { results }
        errorsPrevious: nrql(query: ${q({ nrql: `SELECT count(*) as errorCount FROM TransactionError WHERE ${APP_FILTER} FACET error.class, error.message, transactionName LIMIT 30 SINCE 48 HOURS AGO UNTIL 24 HOURS AGO` })}) { results }
        throughput: nrql(query: ${q({ nrql: `SELECT rate(count(*), 1 minute) as throughput FROM Transaction WHERE ${APP_FILTER} SINCE 24 HOURS AGO TIMESERIES 1 hour` })}) { results }
        throughputMonthly: nrql(query: ${q({ nrql: `SELECT rate(count(*), 1 minute) as throughput FROM Transaction WHERE ${APP_FILTER} SINCE 30 DAYS AGO` })}) { results }
        responseTime: nrql(query: ${q({ nrql: `SELECT average(duration) as avgSec FROM Transaction WHERE ${APP_FILTER} SINCE 24 HOURS AGO TIMESERIES 1 hour` })}) { results }
        responseTimeP95agg: nrql(query: ${q({ nrql: `SELECT percentile(duration, 95) as p95Sec FROM Transaction WHERE ${APP_FILTER} SINCE 24 HOURS AGO` })}) { results }
        responseTimeMonthly: nrql(query: ${q({ nrql: `SELECT average(duration) as avgSec, percentile(duration, 95) as p95Sec FROM Transaction WHERE ${APP_FILTER} SINCE 30 DAYS AGO` })}) { results }
        errorRate: nrql(query: ${q({ nrql: `SELECT percentage(count(*), WHERE error IS true) as errorRate FROM Transaction WHERE ${APP_FILTER} SINCE 24 HOURS AGO TIMESERIES 1 hour` })}) { results }
        errorRateMonthly: nrql(query: ${q({ nrql: `SELECT percentage(count(*), WHERE error IS true) as errorRate FROM Transaction WHERE ${APP_FILTER} SINCE 30 DAYS AGO` })}) { results }
        apdex: nrql(query: ${q({ nrql: `SELECT apdex(duration, t: 0.5) as apdex FROM Transaction WHERE ${APP_FILTER} SINCE 24 HOURS AGO TIMESERIES 1 hour` })}) { results }
        apdexMonthly: nrql(query: ${q({ nrql: `SELECT apdex(duration, t: 0.5) as apdex FROM Transaction WHERE ${APP_FILTER} SINCE 30 DAYS AGO` })}) { results }
        cpu: nrql(query: ${q({ nrql: `SELECT average(cpuPercent) as cpuPercent FROM SystemSample SINCE 24 HOURS AGO TIMESERIES 1 hour` })}) { results }
        memory: nrql(query: ${q({ nrql: `SELECT average(memoryUsedPercent) as memoryPercent FROM SystemSample SINCE 24 HOURS AGO TIMESERIES 1 hour` })}) { results }
        slowQueries: nrql(query: ${q({ nrql: `SELECT max(databaseDuration) * 1000 as maxMs, average(databaseDuration) * 1000 as avgMs, count(*) as count FROM Transaction WHERE ${APP_FILTER} AND databaseDuration > 1 SINCE 24 HOURS AGO FACET name LIMIT 10` })}) { results }
      }
    }
  }`;

	const response = await fetch(NR_GRAPHQL_URL, {
		method: 'POST',
		headers: {
			'Content-Type': 'application/json',
			'API-Key': apiKey,
		},
		body: JSON.stringify({ query }),
	});

	if (!response.ok) {
		throw new Error(`New Relic API error: ${response.status} ${await response.text()}`);
	}

	const json = (await response.json()) as NerdGraphResponse;
	const acct = json.data.actor.account;

	const previousMap = new Map<string, number>();
	for (const row of acct.errorsPrevious.results) {
		const key = `${String(row['error.class'] ?? '')}::${String(row['error.message'] ?? '')}::${String(row['transactionName'] ?? '')}`;
		previousMap.set(key, getField({ row, field: 'errorCount' }));
	}

	const errorGroups: ErrorGroup[] = acct.errorsCurrent.results.map((row) => {
		const errorClass = String(row['error.class'] ?? 'Unknown');
		const errorMessage = String(row['error.message'] ?? '');
		const transactionName = String(row['transactionName'] ?? '');
		const requestUri = String(row['requestUri'] ?? '');
		const count = getField({ row, field: 'errorCount' });
		const key = `${errorClass}::${errorMessage}::${transactionName}`;
		const countPrevious24h = previousMap.get(key) ?? 0;
		const changePercent =
			countPrevious24h === 0
				? null
				: Math.round(((count - countPrevious24h) / countPrevious24h) * 100);
		return {
			errorClass,
			errorMessage,
			transactionName,
			requestUri,
			count,
			countPrevious24h,
			changePercent,
			isNew: countPrevious24h === 0,
		};
	});

	const monthlyThroughputRow = acct.throughputMonthly.results[0];
	const monthlyRtRow = acct.responseTimeMonthly.results[0];
	const monthlyErrorRateRow = acct.errorRateMonthly.results[0];
	const monthlyApdexRow = acct.apdexMonthly.results[0];
	const p95aggRow = acct.responseTimeP95agg.results[0];

	const throughputMonthlyAvg = monthlyThroughputRow
		? getField({ row: monthlyThroughputRow, field: 'throughput' })
		: 0;
	const rtMonthlyAvg = monthlyRtRow
		? getField({ row: monthlyRtRow, field: 'avgSec' }) * 1000
		: 0;
	const rtMonthlyP95 = monthlyRtRow
		? getField({ row: monthlyRtRow, field: 'p95Sec' }) * 1000
		: 0;
	const errorRateMonthlyAvg = monthlyErrorRateRow
		? getField({ row: monthlyErrorRateRow, field: 'errorRate' })
		: 0;
	const apdexMonthlyAvg = monthlyApdexRow
		? getField({ row: monthlyApdexRow, field: 'apdex' })
		: 0;
	const rtP95agg24h = p95aggRow ? getField({ row: p95aggRow, field: 'p95Sec' }) * 1000 : 0;

	const rtP95ChangePercent =
		rtMonthlyP95 === 0
			? null
			: Math.round(((rtP95agg24h - rtMonthlyP95) / rtMonthlyP95) * 100);

	const throughputSeries = buildSeries({
		name: 'Throughput',
		unit: 'req/min',
		rows: acct.throughput.results,
		field: 'throughput',
		monthlyValue: throughputMonthlyAvg,
	});

	const responseTimeSeries = buildSeries({
		name: 'Response Time',
		unit: 'ms',
		rows: acct.responseTime.results,
		field: 'avgSec',
		monthlyValue: rtMonthlyAvg / 1000,
	});

	const responseTimeSeriesInMs: MetricSeries = {
		...responseTimeSeries,
		timeseries: responseTimeSeries.timeseries.map((p) => ({ ...p, value: p.value * 1000 })),
		avg24h: responseTimeSeries.avg24h * 1000,
		monthlyAvg: rtMonthlyAvg,
	};

	const errorRateSeries = buildSeries({
		name: 'Error Rate',
		unit: '%',
		rows: acct.errorRate.results,
		field: 'errorRate',
		monthlyValue: errorRateMonthlyAvg,
	});

	const apdexSeries = buildSeries({
		name: 'Apdex',
		unit: '',
		rows: acct.apdex.results,
		field: 'apdex',
		monthlyValue: apdexMonthlyAvg,
	});

	const cpuRows = acct.cpu.results;
	const memoryRows = acct.memory.results;

	const cpuSeries =
		cpuRows.length === 0
			? null
			: buildSeries({
					name: 'CPU',
					unit: '%',
					rows: cpuRows,
					field: 'cpuPercent',
					monthlyValue: 0,
				});

	const memorySeries =
		memoryRows.length === 0
			? null
			: buildSeries({
					name: 'Memory',
					unit: '%',
					rows: memoryRows,
					field: 'memoryPercent',
					monthlyValue: 0,
				});

	const slowQueries: SlowQuery[] = acct.slowQueries.results
		.filter((row) => getField({ row, field: 'maxMs' }) > 0)
		.map((row) => ({
			transactionName: String(row['name'] ?? ''),
			maxDurationMs: Math.round(getField({ row, field: 'maxMs' })),
			avgDurationMs: Math.round(getField({ row, field: 'avgMs' })),
			count: Math.round(getField({ row, field: 'count' })),
		}));

	const comparison: MetricComparison[] = [
		{
			label: 'Throughput',
			value24h: Math.round(throughputSeries.avg24h * 10) / 10,
			valueMonthly: Math.round(throughputMonthlyAvg * 10) / 10,
			changePercent: throughputSeries.changePercent,
			unit: 'req/min',
		},
		{
