export interface MetricPoint {
	beginTimeSeconds: number;
	endTimeSeconds: number;
	value: number;
}

export interface MetricSeries {
	name: string;
	unit: string;
	timeseries: MetricPoint[];
	avg24h: number;
	monthlyAvg: number;
	changePercent: number | null;
}

export interface ErrorGroup {
	errorClass: string;
	errorMessage: string;
	transactionName: string;
	requestUri: string;
	count: number;
	countPrevious24h: number;
	changePercent: number | null;
	isNew: boolean;
}

export type AlertType =
	| 'SPIKE'
	| 'DOWNTIME'
	| 'HIGH_ERROR_RATE'
	| 'SLOW_RESPONSE'
	| 'HIGH_CPU'
	| 'NEW_ERROR';

export interface Alert {
	type: AlertType;
	metric: string;
	currentValue: number;
	threshold: number;
	severity: 'WARNING' | 'CRITICAL';
	description: string;
}

export interface SlowQuery {
	transactionName: string;
	maxDurationMs: number;
	avgDurationMs: number;
	count: number;
}

export interface MetricComparison {
	label: string;
	value24h: number;
	valueMonthly: number;
	changePercent: number | null;
	unit: string;
}

export interface Digest {
	generatedAt: string;
	period: {
		from: string;
		to: string;
	};
	errors: {
		total24h: number;
		newErrors: number;
		groups: ErrorGroup[];
	};
	metrics: {
		throughput: MetricSeries;
		responseTime: MetricSeries;
		errorRate: MetricSeries;
		apdex: MetricSeries;
		cpu: MetricSeries | null;
		memory: MetricSeries | null;
	};
	comparison: MetricComparison[];
	slowQueries: SlowQuery[];
	alerts: Alert[];
}

