		alerts.push({
			type: 'HIGH_ERROR_RATE' as AlertType,
			metric: 'Error Rate',
			currentValue: Math.round(errorRate * 100) / 100,
			threshold: THRESHOLDS.errorRate.warning,
			severity: 'WARNING',
			description: `Error rate ${errorRate.toFixed(2)}% exceeds warning threshold of ${THRESHOLDS.errorRate.warning}%`,
		});
	}

	if (responseTimeMs >= THRESHOLDS.responseTimeAvgMs.critical) {
		alerts.push({
			type: 'SLOW_RESPONSE' as AlertType,
			metric: 'Response Time',
			currentValue: Math.round(responseTimeMs),
			threshold: THRESHOLDS.responseTimeAvgMs.critical,
			severity: 'CRITICAL',
			description: `Avg response time ${Math.round(responseTimeMs)}ms exceeds critical threshold of ${THRESHOLDS.responseTimeAvgMs.critical}ms`,
		});
	} else if (responseTimeMs >= THRESHOLDS.responseTimeAvgMs.warning) {
		alerts.push({
			type: 'SLOW_RESPONSE' as AlertType,
			metric: 'Response Time',
			currentValue: Math.round(responseTimeMs),
			threshold: THRESHOLDS.responseTimeAvgMs.warning,
			severity: 'WARNING',
			description: `Avg response time ${Math.round(responseTimeMs)}ms exceeds warning threshold of ${THRESHOLDS.responseTimeAvgMs.warning}ms`,
		});
	}

	if (apdex > 0 && apdex <= THRESHOLDS.apdex.critical) {
		alerts.push({
			type: 'SLOW_RESPONSE' as AlertType,
			metric: 'Apdex',
			currentValue: Math.round(apdex * 1000) / 1000,
			threshold: THRESHOLDS.apdex.critical,
			severity: 'CRITICAL',
			description: `Apdex ${apdex.toFixed(3)} below critical threshold of ${THRESHOLDS.apdex.critical}`,
		});
	} else if (apdex > 0 && apdex <= THRESHOLDS.apdex.warning) {
		alerts.push({
			type: 'SLOW_RESPONSE' as AlertType,
			metric: 'Apdex',
			currentValue: Math.round(apdex * 1000) / 1000,
			threshold: THRESHOLDS.apdex.warning,
			severity: 'WARNING',
			description: `Apdex ${apdex.toFixed(3)} below warning threshold of ${THRESHOLDS.apdex.warning}`,
		});
	}

	if (throughputMonthly > 0 && throughputCurrent > 0) {
		const dropPct = ((throughputCurrent - throughputMonthly) / throughputMonthly) * 100;
		if (dropPct <= THRESHOLDS.throughputDropPercent) {
			alerts.push({
				type: 'DOWNTIME' as AlertType,
				metric: 'Throughput',
				currentValue: Math.round(throughputCurrent * 10) / 10,
				threshold: throughputMonthly,
				severity: 'CRITICAL',
				description: `Throughput dropped ${Math.abs(Math.round(dropPct))}% vs 30-day average — possible downtime or traffic loss`,
			});
		}
	}

	return alerts;
}

async function run(): Promise<void> {
	const apiKey = process.env['NEW_RELIC_API_KEY'];
	const accountId = process.env['NEW_RELIC_ACCOUNT_ID'];

	if (!apiKey) throw new Error('NEW_RELIC_API_KEY is required');
	if (!accountId) throw new Error('NEW_RELIC_ACCOUNT_ID is required');

	console.log('Fetching New Relic metrics (last 24h vs 30-day baseline)...');

	const now = new Date();
	const since24h = new Date(now.getTime() - 86400 * 1000);

	const {
		errorGroups,
		throughput,
		responseTime,
		errorRate,
		apdex,
		slowQueries,
		comparison,
	} = await fetchNewRelicMetrics({ apiKey, accountId });

	console.log(
		`Fetched: ${errorGroups.length} error groups, ${slowQueries.length} slow queries`,
	);

	const newErrors = errorGroups.filter((e) => e.isNew).length;
	const total24h = errorGroups.reduce((sum, e) => sum + e.count, 0);

	const thresholdAlerts = detectAlerts({
		errorRate: errorRate.avg24h,
		responseTimeMs: responseTime.avg24h,
		apdex: apdex.avg24h,
		throughputCurrent: throughput.avg24h,
		throughputMonthly: throughput.monthlyAvg,
	});

	const newErrorAlerts: Alert[] = errorGroups
		.filter((e) => e.isNew && e.count > 10)
		.map((e) => ({
			type: 'NEW_ERROR' as AlertType,
			metric: 'Error',
			currentValue: e.count,
			threshold: 0,
			severity: 'WARNING' as const,
			description: `New error: ${e.errorClass}${e.errorMessage ? ` — ${e.errorMessage}` : ''} (${e.count} occurrences)`,
		}));

	const digest: Digest = {
		generatedAt: now.toISOString(),
		period: {
			from: since24h.toISOString(),
			to: now.toISOString(),
		},
		errors: {
			total24h,
			newErrors,
			groups: errorGroups,
		},
		metrics: {
			throughput,
			responseTime,
			errorRate,
			apdex,
			cpu,
			memory,
		},
		comparison,
		slowQueries,
		alerts: [...thresholdAlerts, ...newErrorAlerts],
	};

	writeFileSync('newrelic-digest.json', JSON.stringify(digest, null, 2));

	console.log(
		`Digest written to newrelic-digest.json — errors: ${total24h} (${newErrors} new), alerts: ${digest.alerts.length}`,
	);
}

run().catch((err: unknown) => {
	console.error('New Relic monitor failed:', err);
	process.exit(1);
});

