			'API-Key': apiKey,
		},
		body: JSON.stringify({ query }),
	});

	if (!response.ok) {
		throw new Error(`New Relic API error: ${response.status} ${await response.text()}`);
	}

	const json = (await response.json()) as NerdGraphResponse;
	const acct = json.data.actor.account;

	const previousMap = new Map<string, number>();
	for (const row of acct.errorsPrevious.results) {
		const key = `${String(row['error.class'] ?? '')}::${String(row['error.message'] ?? '')}::${String(row['transactionName'] ?? '')}`;
		previousMap.set(key, getField({ row, field: 'errorCount' }));
	}

	const errorGroups: ErrorGroup[] = acct.errorsCurrent.results.map((row) => {
		const errorClass = String(row['error.class'] ?? 'Unknown');
		const errorMessage = String(row['error.message'] ?? '');
		const transactionName = String(row['transactionName'] ?? '');
		const requestUri = String(row['requestUri'] ?? '');
		const count = getField({ row, field: 'errorCount' });
		const key = `${errorClass}::${errorMessage}::${transactionName}`;
		const countPrevious24h = previousMap.get(key) ?? 0;
		const changePercent =
			countPrevious24h === 0
				? null
				: Math.round(((count - countPrevious24h) / countPrevious24h) * 100);
		return {
			errorClass,
			errorMessage,
			transactionName,
			requestUri,
			count,
			countPrevious24h,
			changePercent,
			isNew: countPrevious24h === 0,
		};
	});

	const monthlyThroughputRow = acct.throughputMonthly.results[0];
	const monthlyRtRow = acct.responseTimeMonthly.results[0];
	const monthlyErrorRateRow = acct.errorRateMonthly.results[0];
	const monthlyApdexRow = acct.apdexMonthly.results[0];
	const p95aggRow = acct.responseTimeP95agg.results[0];

	const throughputMonthlyAvg = monthlyThroughputRow
		? getField({ row: monthlyThroughputRow, field: 'throughput' })
		: 0;
	const rtMonthlyAvg = monthlyRtRow
		? getField({ row: monthlyRtRow, field: 'avgSec' }) * 1000
		: 0;
	const rtMonthlyP95 = monthlyRtRow
		? getField({ row: monthlyRtRow, field: 'p95Sec' }) * 1000
		: 0;
	const errorRateMonthlyAvg = monthlyErrorRateRow
		? getField({ row: monthlyErrorRateRow, field: 'errorRate' })
		: 0;
	const apdexMonthlyAvg = monthlyApdexRow
		? getField({ row: monthlyApdexRow, field: 'apdex' })
		: 0;
	const rtP95agg24h = p95aggRow ? getField({ row: p95aggRow, field: 'p95Sec' }) * 1000 : 0;

	const rtP95ChangePercent =
		rtMonthlyP95 === 0
			? null
			: Math.round(((rtP95agg24h - rtMonthlyP95) / rtMonthlyP95) * 100);

	const throughputSeries = buildSeries({
		name: 'Throughput',
		unit: 'req/min',
		rows: acct.throughput.results,
		field: 'throughput',
		monthlyValue: throughputMonthlyAvg,
	});

	const responseTimeSeries = buildSeries({
		name: 'Response Time',
		unit: 'ms',
		rows: acct.responseTime.results,
		field: 'avgSec',
		monthlyValue: rtMonthlyAvg / 1000,
	});

	const responseTimeSeriesInMs: MetricSeries = {
		...responseTimeSeries,
		timeseries: responseTimeSeries.timeseries.map((p) => ({ ...p, value: p.value * 1000 })),
		avg24h: responseTimeSeries.avg24h * 1000,
		monthlyAvg: rtMonthlyAvg,
	};

	const errorRateSeries = buildSeries({
		name: 'Error Rate',
		unit: '%',
		rows: acct.errorRate.results,
		field: 'errorRate',
		monthlyValue: errorRateMonthlyAvg,
	});

	const apdexSeries = buildSeries({
		name: 'Apdex',
		unit: '',
		rows: acct.apdex.results,
		field: 'apdex',
		monthlyValue: apdexMonthlyAvg,
	});

	const slowQueries: SlowQuery[] = acct.slowQueries.results
		.filter((row) => getField({ row, field: 'maxMs' }) > 0)
		.map((row) => ({
			transactionName: String(row['name'] ?? ''),
			maxDurationMs: Math.round(getField({ row, field: 'maxMs' })),
			avgDurationMs: Math.round(getField({ row, field: 'avgMs' })),
			count: Math.round(getField({ row, field: 'count' })),
		}));

	const comparison: MetricComparison[] = [
		{
			label: 'Throughput',
			value24h: Math.round(throughputSeries.avg24h * 10) / 10,
			valueMonthly: Math.round(throughputMonthlyAvg * 10) / 10,
			changePercent: throughputSeries.changePercent,
			unit: 'req/min',
		},
		{
			label: 'Response Time (avg)',
			value24h: Math.round(responseTimeSeriesInMs.avg24h),
			valueMonthly: Math.round(rtMonthlyAvg),
			changePercent: responseTimeSeriesInMs.changePercent,
			unit: 'ms',
		},
		{
			label: 'Response Time (P95)',
			value24h: Math.round(rtP95agg24h),
			valueMonthly: Math.round(rtMonthlyP95),
			changePercent: rtP95ChangePercent,
			unit: 'ms',
		},
		{
			label: 'Error Rate',
			value24h: Math.round(errorRateSeries.avg24h * 100) / 100,
			valueMonthly: Math.round(errorRateMonthlyAvg * 100) / 100,
			changePercent: errorRateSeries.changePercent,
			unit: '%',
		},
		{
			label: 'Apdex',
			value24h: Math.round(apdexSeries.avg24h * 1000) / 1000,
			valueMonthly: Math.round(apdexMonthlyAvg * 1000) / 1000,
			changePercent: apdexSeries.changePercent,
			unit: '',
		},
	];

	return {
		errorGroups,
		throughput: throughputSeries,
		responseTime: responseTimeSeriesInMs,
		errorRate: errorRateSeries,
		apdex: apdexSeries,
		slowQueries,
		comparison,
	};
}

import { writeFileSync } from 'node:fs';

import { fetchNewRelicMetrics } from './newrelic-client';
import type { Alert, AlertType, Digest } from './types';

const THRESHOLDS = {
	errorRate: { warning: 1, critical: 5 },
	responseTimeAvgMs: { warning: 1000, critical: 2000 },
	apdex: { warning: 0.85, critical: 0.7 },
	throughputDropPercent: -50,
} as const;

function detectAlerts({
	errorRate,
	responseTimeMs,
	apdex,
	throughputCurrent,
	throughputMonthly,
}: {
	errorRate: number;
	responseTimeMs: number;
	apdex: number;
	throughputCurrent: number;
	throughputMonthly: number;
}): Alert[] {
	const alerts: Alert[] = [];

	if (errorRate >= THRESHOLDS.errorRate.critical) {
		alerts.push({
			type: 'HIGH_ERROR_RATE' as AlertType,
			metric: 'Error Rate',
			currentValue: Math.round(errorRate * 100) / 100,
			threshold: THRESHOLDS.errorRate.critical,
			severity: 'CRITICAL',
			description: `Error rate ${errorRate.toFixed(2)}% exceeds critical threshold of ${THRESHOLDS.errorRate.critical}%`,
		});
	} else if (errorRate >= THRESHOLDS.errorRate.warning) {
		alerts.push({
			type: 'HIGH_ERROR_RATE' as AlertType,
			metric: 'Error Rate',
			currentValue: Math.round(errorRate * 100) / 100,
			threshold: THRESHOLDS.errorRate.warning,
			severity: 'WARNING',
			description: `Error rate ${errorRate.toFixed(2)}% exceeds warning threshold of ${THRESHOLDS.errorRate.warning}%`,
		});
	}

	if (responseTimeMs >= THRESHOLDS.responseTimeAvgMs.critical) {
		alerts.push({
			type: 'SLOW_RESPONSE' as AlertType,
			metric: 'Response Time',
			currentValue: Math.round(responseTimeMs),
			threshold: THRESHOLDS.responseTimeAvgMs.critical,
			severity: 'CRITICAL',
			description: `Avg response time ${Math.round(responseTimeMs)}ms exceeds critical threshold of ${THRESHOLDS.responseTimeAvgMs.critical}ms`,
		});
	} else if (responseTimeMs >= THRESHOLDS.responseTimeAvgMs.warning) {
		alerts.push({
			type: 'SLOW_RESPONSE' as AlertType,
			metric: 'Response Time',
			currentValue: Math.round(responseTimeMs),
			threshold: THRESHOLDS.responseTimeAvgMs.warning,
			severity: 'WARNING',
			description: `Avg response time ${Math.round(responseTimeMs)}ms exceeds warning threshold of ${THRESHOLDS.responseTimeAvgMs.warning}ms`,
		});
	}

	if (apdex > 0 && apdex <= THRESHOLDS.apdex.critical) {
		alerts.push({
			type: 'SLOW_RESPONSE' as AlertType,
			metric: 'Apdex',
			currentValue: Math.round(apdex * 1000) / 1000,
			threshold: THRESHOLDS.apdex.critical,
			severity: 'CRITICAL',
			description: `Apdex ${apdex.toFixed(3)} below critical threshold of ${THRESHOLDS.apdex.critical}`,
		});
	} else if (apdex > 0 && apdex <= THRESHOLDS.apdex.warning) {
		alerts.push({
			type: 'SLOW_RESPONSE' as AlertType,
			metric: 'Apdex',
			currentValue: Math.round(apdex * 1000) / 1000,
			threshold: THRESHOLDS.apdex.warning,
			severity: 'WARNING',
			description: `Apdex ${apdex.toFixed(3)} below warning threshold of ${THRESHOLDS.apdex.warning}`,
		});
	}

	if (throughputMonthly > 0 && throughputCurrent > 0) {
		const dropPct = ((throughputCurrent - throughputMonthly) / throughputMonthly) * 100;
		if (dropPct <= THRESHOLDS.throughputDropPercent) {
			alerts.push({
				type: 'DOWNTIME' as AlertType,
				metric: 'Throughput',
				currentValue: Math.round(throughputCurrent * 10) / 10,
				threshold: throughputMonthly,
				severity: 'CRITICAL',
				description: `Throughput dropped ${Math.abs(Math.round(dropPct))}% vs 30-day average — possible downtime or traffic loss`,
			});
		}
	}

	return alerts;
}

async function run(): Promise<void> {
	const apiKey = process.env['NEW_RELIC_API_KEY'];
	const accountId = process.env['NEW_RELIC_ACCOUNT_ID'];

	if (!apiKey) throw new Error('NEW_RELIC_API_KEY is required');
	if (!accountId) throw new Error('NEW_RELIC_ACCOUNT_ID is required');

	console.log('Fetching New Relic metrics (last 24h vs 30-day baseline)...');

	const now = new Date();
	const since24h = new Date(now.getTime() - 86400 * 1000);

	const {
		errorGroups,
		throughput,
		responseTime,
		errorRate,
		apdex,
		slowQueries,
		comparison,
	} = await fetchNewRelicMetrics({ apiKey, accountId });

	console.log(
		`Fetched: ${errorGroups.length} error groups, ${slowQueries.length} slow queries`,
	);

	const newErrors = errorGroups.filter((e) => e.isNew).length;
	const total24h = errorGroups.reduce((sum, e) => sum + e.count, 0);

	const thresholdAlerts = detectAlerts({
		errorRate: errorRate.avg24h,
		responseTimeMs: responseTime.avg24h,
		apdex: apdex.avg24h,
		throughputCurrent: throughput.avg24h,
		throughputMonthly: throughput.monthlyAvg,
	});

	const newErrorAlerts: Alert[] = errorGroups
		.filter((e) => e.isNew && e.count > 10)
		.map((e) => ({
			type: 'NEW_ERROR' as AlertType,
			metric: 'Error',
			currentValue: e.count,
			threshold: 0,
			severity: 'WARNING' as const,
			description: `New error: ${e.errorClass}${e.errorMessage ? ` — ${e.errorMessage}` : ''} (${e.count} occurrences)`,
		}));

	const digest: Digest = {
		generatedAt: now.toISOString(),
		period: {
			from: since24h.toISOString(),
			to: now.toISOString(),
		},
		errors: {
			total24h,
			newErrors,
			groups: errorGroups,
		},
		metrics: {
			throughput,
			responseTime,
			errorRate,
			apdex,
		},
		comparison,
		slowQueries,
		alerts: [...thresholdAlerts, ...newErrorAlerts],
	};

	writeFileSync('newrelic-digest.json', JSON.stringify(digest, null, 2));

	console.log(
		`Digest written to newrelic-digest.json — errors: ${total24h} (${newErrors} new), alerts: ${digest.alerts.length}`,
	);
}

run().catch((err: unknown) => {
	console.error('New Relic monitor failed:', err);
	process.exit(1);
});

# Environment Variables

**ALWAYS follow this complete 5-step process when adding new environment variables. Missing any step causes validation failures at startup.**

## Step 1: Add to Environment Files

```bash
# .env
NEW_VARIABLE_NAME=default_value_or_placeholder # Description of what this variable does

# .env.test
NEW_VARIABLE_NAME=default_value_or_placeholder # Description of what this variable does

# .env.example
NEW_VARIABLE_NAME=default_value_or_placeholder # Description of what this variable does

# .env.test.example
NEW_VARIABLE_NAME=test_value # Use appropriate test value
```

## Step 2: Create Constant Export

`src/constants/env-variables.constant.ts`:

```typescript
export const NEW_VARIABLE_NAME = 'NEW_VARIABLE_NAME';
```

## Step 3: Add Validation Rule

`src/configs/env-validations.config.ts` in the `EnvironmentVariables` class:

```typescript
@IsString() // @IsString() | @IsNumber() | @IsBoolean() | @IsEnum(EnumType)
@IsNotEmpty() // add @Min() / @Max() for numeric constraints
NEW_VARIABLE_NAME: string;
```

## Step 4: Add to Environment Loader

`src/utils/get-env-file.util.ts` in `getEnvVariables()`:

```typescript
export const getEnvVariables = (): Record<string, string | number | undefined> => ({
	// ... existing variables
	NEW_VARIABLE_NAME: process.env['NEW_VARIABLE_NAME'],
});
```

## Step 5: Add Test Coverage

`test/env-config.module.e2e-spec.ts`:

```typescript
// In beforeAll hook
testEnvVariables['NEW_VARIABLE_NAME'] = String(envConfig['NEW_VARIABLE_NAME']);

// Test case
it('should load NEW_VARIABLE_NAME correctly', () => {
	expect(envConfigService.get<string>({ key: NEW_VARIABLE_NAME })).toBe(
		testEnvVariables['NEW_VARIABLE_NAME'],
	);
});
```

## Usage

**Approach 1: EnvConfigService (preferred in injectable classes)**

```typescript
import { EnvConfigService } from '@modules/env-config/env-config.service';
import { NEW_VARIABLE_NAME } from '@constants/env-variables.constant';

const value = this.configService.get<string>({ key: NEW_VARIABLE_NAME });
const num = this.configService.get<number>({ key: NEW_VARIABLE_NAME, converter: Number });
```

**Approach 2: getEnv (standalone / outside DI)**

```typescript
import { getEnv } from '@utils/get-env-variable.util';
import { NEW_VARIABLE_NAME } from '@constants/env-variables.constant';

const value = getEnv<string>({ key: NEW_VARIABLE_NAME });
const num = getEnv<number>({ key: NEW_VARIABLE_NAME, converter: Number });
```

## Rules

- **NEVER** access `process.env` directly in application code
- **ALWAYS** use constants from `@constants/env-variables.constant`
- Validation runs on startup and fails fast if misconfigured
- Verify with `npm run test:e2e` after adding

