const d = JSON.parse(require('fs').readFileSync('/dev/stdin','utf8'));
const vulns = Object.values(d.vulnerabilities);
const grouped = {};
vulns.forEach(v => {
  const key = v.severity;
  if (!grouped[key]) grouped[key] = [];
  grouped[key].push({ name: v.name, via: v.via.filter(x => typeof x === 'object').map(x => x.title || x.name).join(', '), fixAvailable: v.fixAvailable });
});
Object.entries(grouped).forEach(([sev, items]) => {
  console.log('\n=== ' + sev.toUpperCase() + ' ===');
  items.forEach(i => console.log(i.name + ' | ' + i.via + ' | fix: ' + JSON.stringify(i.fixAvailable)));
});
" 2>/dev/null

